6745050506271953949139230097128034416815169649874760890189515620232505703162831090225715453502422905418824316957257395992121750661389503495033, 22074209373194902539215367382758486068533032275912313703269990627206774967653336496619231924013216321042649461711292555464574124714934511202231319963361912937842068483700298097209400217869036338644607607557860, 19678336511265998427322297909733474384702243426420286924671444552444079816707773485084891630780465895504253899943221044355971296122774264925882685351095921532685536165514189427245840338009573352081361238596378, 24746314790210393213546150322117518542380438001687269872679602687597595933350510598742749840102841364627647151669428936678130556027300886850086220074563664367409218038338623691372433831784916816798993162471163, 19346137206512895254202370018555139713690272833895195472766704715282164091959131850520571672509601848193468792313437642997923790118115476212663296111963644011010744006086847599108492279986468255445160241848708, 22739514514055088545643169404630736699361136323546717268615404574809011342622362833245601099992039789664042350284789853188040159950619203242924511038681127008964592137006103547262538912024671048254652547084347, 21491512279698208400974501713300096639215882495977078132548631606796810881149011161903684894826752520167909538856354238104288201344211604223297924253960199754326239113862002469224042442018978623149685130901455, 19381008151938129775129563507607725859173925946797075261437001349051037306091047611533900186593946739906685481456985573476863123716331923469386565432105662324849798182175616351721533048174745501978394238803081, 19965143096260141101824772370858657624912960190922708879345774507598595008331705725441057080530773097285721556537121282837594544143441953208783728710383586054502176671726097169651121269564738513585870857829805]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;k = 2^(512 - 180)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;M = Matrix.column([k * v for v in V]).augment(Matrix.identity(len(V)))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;B = [b[1:] for b in M.LLL()]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;M = (k * Matrix(B[:len(V)-2])).T.augment(Matrix.identity(len(V)))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;B = [b[-len(V):] for b in M.LLL() if set(b[:len(V)-2]) == &amp;#123;0&amp;#125;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for s, t in itertools.product(range(100), repeat=2):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    T = s*B[0] + t*B[1]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    a1, a2, a3 = T[0], T[1], T[2]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    kq = gcd(a1 * hints[1] - a2 * hints[0], n)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if 1 &amp;lt; kq &amp;lt; n:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        print(&amp;#x27;find!&amp;#x27;, kq, s, t)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        break&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for i in range(2**16, 1, -1):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if kq % i == 0:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        kq //= i&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;q = int(kq)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;p = int(n // kq)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;#x27;p&amp;#x27;, p)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;#x27;q&amp;#x27;,q)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#8112940945910485817171807897687451701452029959677470272197529542411816926233172848066074195817612280582244564398252967013953964546888998662975298338523549 0 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9067773077510925207378520309595658022345214442920360440202890774224295250116442048990578009377300541280465330975931465993745130297479191298485033569345231&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8112940945910485817171807897687451701452029959677470272197529542411816926233172848066074195817612280582244564398252967013953964546888998662975298338523549&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;得到，p，q 直接解出第二部分&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;from Crypto.Util.number import long_to_bytes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;from gmpy2 import gmpy2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# kq, s, t = 8112940945910485817171807897687451701452029959677470272197529542411816926233172848066074195817612280582244564398252967013953964546888998662975298338523549 0 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;p = 9067773077510925207378520309595658022345214442920360440202890774224295250116442048990578009377300541280465330975931465993745130297479191298485033569345231&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;q = 8112940945910485817171807897687451701452029959677470272197529542411816926233172848066074195817612280582244564398252967013953964546888998662975298338523549&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n, e = (, 65537)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c2 = &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&l